# Configure structured logging - NEVER log sensitive data
logger = logging.getLogger(__name__)
logger.setLevel(getattr(logging, os.environ.get("LOG_LEVEL", "INFO")))

# Sensitive field names that must never appear in logs
SENSITIVE_FIELDS = frozenset({
    "password", "secret", "token", "api_key", "apikey", "authorization",
    "auth", "credential", "ssn", "credit_card", "card_number", "cvv",
    "private_key", "access_key", "secret_key", "session_token",
})

# Environment configuration with validation
ENVIRONMENT = os.environ.get("ENVIRONMENT", "dev")
ALLOWED_ENVIRONMENTS = {"dev", "staging", "prod"}
if ENVIRONMENT not in ALLOWED_ENVIRONMENTS:
    raise ValueError(f"Invalid environment: must be one of {ALLOWED_ENVIRONMENTS}")

TABLE_NAME = os.environ.get("DYNAMODB_TABLE", f"microservices-data-{ENVIRONMENT}")
S3_BUCKET = os.environ.get("S3_BUCKET", f"microservices-data-{ENVIRONMENT}")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "")
AWS_REGION = os.environ.get("AWS_REGION", "us-east-1")

# Boto3 client configuration with retry and timeout settings
BOTO_CONFIG = Config(
    region_name=AWS_REGION,
    retries={"max_attempts": 3, "mode": "adaptive"},
    connect_timeout=5,
    read_timeout=10,
)

# Input validation constants
MAX_INPUT_LENGTH = 10_000
MAX_KEY_LENGTH = 256
ALLOWED_S3_KEY_PATTERN = re.compile(r"^[a-zA-Z0-9\-_./]{1,1024}$")
ALLOWED_ID_PATTERN = re.compile(r"^[a-zA-Z0-9\-_]{1,128}$")
ALLOWED_ACTIONS = frozenset({"get", "put", "delete", "list", "publish", "enqueue"})


class InputValidationError(Exception):
    """Raised when input validation fails."""
    pass


class AuthorizationError(Exception):
    """Raised when authorization check fails."""
    pass


def sanitize_for_logging(data: Any, depth: int = 0) -> Any:
    """
    Recursively sanitize data to remove sensitive fields before logging.
    Prevents accidental exposure of secrets, tokens, PII in CloudWatch logs.
    """
    if depth > 10:
        return "[TRUNCATED - MAX DEPTH]"

    if isinstance(data, dict):
        sanitized = {}
        for key, value in data.items():
            lower_key = str(key).lower().replace("-", "_").replace(" ", "_")
            if any(sensitive in lower_key for sensitive in SENSITIVE_FIELDS):
                sanitized[key] = "[REDACTED]"
            else:
                sanitized[key] = sanitize_for_logging(value, depth + 1)
        return sanitized
    elif isinstance(data, (list, tuple)):
        return [sanitize_for_logging(item, depth + 1) for item in data[:100]]
    elif isinstance(data, str) and len(data) > 1000:
        return data[:100] + "...[TRUNCATED]"
    return data


def validate_string_input(value: Any, field_name: str, pattern: re.Pattern,
                          max_length: int = MAX_KEY_LENGTH, required: bool = True) -> Optional[str]:
    """Validate a string input against a pattern and length constraint."""
    if value is None or value == "":
        if required:
            raise InputValidationError(f"Missing required field: {field_name}")
        return None

    if not isinstance(value, str):
        raise InputValidationError(f"Field '{field_name}' must be a string")

    if len(value) > max_length:
        raise InputValidationError(
            f"Field '{field_name}' exceeds maximum length of {max_length}"
        )

    if not pattern.match(value):
        raise InputValidationError(
            f"Field '{field_name}' contains invalid characters"
        )

    return value


def validate_action(action: str) -> str:
    """Validate that the requested action is in the allowlist."""
    if not isinstance(action, str):
        raise InputValidationError("Action must be a string")

    action_lower = action.lower().strip()
    if action_lower not in ALLOWED_ACTIONS:
        raise InputValidationError(
            f"Invalid action: must be one of {sorted(ALLOWED_ACTIONS)}"
        )
    return action_lower


def validate_request_body(body: Any) -> dict:
    """Validate and parse the request body."""
    if body is None:
        return {}

    if isinstance(body, str):
        if len(body) > MAX_INPUT_LENGTH:
            raise InputValidationError(
                f"Request body exceeds maximum length of {MAX_INPUT_LENGTH}"
            )
        try:
            parsed = json.loads(body)
        except (json.JSONDecodeError, TypeError) as e:
            raise InputValidationError(f"Invalid JSON in request body: {e}")
    elif isinstance(body, dict):
        parsed = body
    else:
        raise InputValidationError("Request body must be a JSON string or dict")

    if not isinstance(parsed, dict):
        raise InputValidationError("Request body must be a JSON object")

    return parsed


def require_auth(func):
    """
    Decorator to enforce authentication/authorization checks.
    Validates that the request has proper authorization context from API Gateway/ALB.
    """
    @wraps(func)
    def wrapper(event, context):
        request_context = event.get("requestContext", {})

        # Check for API Gateway authorizer context
        authorizer = request_context.get("authorizer", {})
        identity = request_context.get("identity", {})

        # Verify caller identity exists (set by API Gateway authorizer)
        caller_id = authorizer.get("principalId") or authorizer.get("claims", {}).get("sub")

        if not caller_id:
            # For internal service-to-service calls, verify source
            source_arn = event.get("Records", [{}])[0].get("eventSourceARN", "") if event.get("Records") else ""
            invoke_source = event.get("source", "")

            # Allow known internal event sources
            allowed_internal_sources = {
                "aws.events",
                "aws.s3",
                "aws.dynamodb",
                "aws.sqs",
                "aws.sns",
            }

            is_internal = (
                invoke_source in allowed_internal_sources
                or any(
                    source_arn.startswith(f"arn:aws:{svc}")
                    for svc in ["sqs", "sns", "dynamodb", "s3", "events"]
                )
            )

            if not is_internal:
                logger.warning(
                    "Unauthorized access attempt",
                    extra={"source_ip": identity.get("sourceIp", "unknown")},
                )
                raise AuthorizationError("Unauthorized: No valid authentication context")

        return func(event, context)

    return wrapper


def get_boto3_client(service_name: str):
    """Create a boto3 client with standard configuration."""
    return boto3.client(service_name, config=BOTO_CONFIG)


def get_boto3_resource(service_name: str):
    """Create a boto3 resource with standard configuration."""
    return boto3.resource(service_name, config=BOTO_CONFIG)


class SecureSecretsManager:
    """
    Securely retrieve secrets from AWS Secrets Manager.
    Caches secrets in memory (within Lambda execution context) to reduce API calls.
    Never logs or exposes secret values.
    """

    _cache: dict = {}
    _cache_ttl: dict = {}
    CACHE_DURATION = 300  # 5 minutes

    @classmethod
    def get_secret(cls, secret_name: str) -> str:
        """Retrieve a secret value from Secrets Manager with caching."""
        # Validate secret name
        if not re.match(r"^[a-zA-Z0-9/_\-\.]{1,512}$", secret_name):
            raise InputValidationError("Invalid secret name format")

        now = time.time()
        if secret_name in cls._cache and cls._cache_ttl.get(secret_name, 0) > now:
            return cls._cache[secret_name]

        try:
            client = get_boto3_client("secretsmanager")
            response = client.get_secret_value(
                SecretId=f"microservices/{ENVIRONMENT}/{secret_name}"
            )
            secret_value = response["SecretString"]
            cls._cache[secret_name] = secret_value
            cls._cache_ttl[secret_name] = now + cls.CACHE_DURATION
            logger.info("Secret retrieved successfully", extra={"secret_name": secret_name})
            return secret_value
        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            logger.error(
                "Failed to retrieve secret",
                extra={"secret_name": secret_name, "error_code": error_code},
            )
            raise


class DynamoDBService:
    """Secure DynamoDB operations with input validation."""

    def __init__(self):
        self._table = get_boto3_resource("dynamodb").Table(TABLE_NAME)

    def get_item(self, item_id: str) -> Optional[dict]:
        """Retrieve an item by ID with input validation."""
        validated_id = validate_string_input(item_id, "item_id", ALLOWED_ID_PATTERN)

        try:
            response = self._table.get_item(
                Key={"id": validated_id},
                ConsistentRead=False,
            )
            item = response.get("Item")
            if item:
                logger.info("Item retrieved", extra={"item_id": validated_id})
            return item
        except ClientError as e:
            logger.error(
                "DynamoDB get_item failed",
                extra={
                    "item_id": validated_id,
                    "error_code": e.response["Error"]["Code"],
                },
            )
            raise

    def put_item(self, item_id: str, data: dict) -> dict:
        """Store an item with input validation."""
        validated_id = validate_string_input(item_id, "item_id", ALLOWED_ID_PATTERN)

        # Sanitize data - remove any sensitive fields from being stored in plaintext
        sanitized_data = {}
        for key, value in data.items():
            if not isinstance(key, str) or len(key) > MAX_KEY_LENGTH:
                continue
            lower_key = key.lower().replace("-", "_").replace(" ", "_")
            if any(sensitive in lower_key for sensitive in SENSITIVE_FIELDS):
                logger.warning(
                    "Attempted to store sensitive field in plaintext - skipping",
                    extra={"field_name": key},
                )
                continue
            sanitized_data[key] = value

        item = {
            "id": validated_id,
            "data": sanitized_data,
            "environment": ENVIRONMENT,
            "updated_at": Decimal(str(time.time())),
        }

        try:
            self._table.put_item(Item=item)
            logger.info("Item stored", extra={"item_id": validated_id})
            return {"id": validated_id, "status": "created"}
        except ClientError as e:
            logger.error(
                "DynamoDB put_item failed",
                extra={
                    "item_id": validated_id,
                    "error_code": e.response["Error"]["Code"],
                },
            )
            raise

    def delete_item(self, item_id: str) -> dict:
        """Delete an item with input validation."""
        validated_id = validate_string_input(item_id, "item_id", ALLOWED_ID_PATTERN)

        try:
            self._table.delete_item(Key={"id": validated_id})
            logger.info("Item deleted", extra={"item_id": validated_id})
            return {"id": validated_id, "status": "deleted"}
        except ClientError as e:
            logger.error(
                "DynamoDB delete_item failed",
                extra={
                    "item_id": validated_id,
                    "error_code": e.response["Error"]["Code"],
                },
            )
            raise


class S3Service:
    """Secure S3 operations with input validation and path traversal prevention."""

    def __init__(self):
        self._client = get_boto3_client("s3")

    def _validate_s3_key(self, key: str) -> str:
        """Validate S3 key to prevent path traversal and injection."""
        validated = validate_string_input(key, "s3_key", ALLOWED_S3_KEY_PATTERN, max_length=1024)

        # Prevent path traversal
        if ".." in validated or validated.startswith("/"):
            raise InputValidationError("S3 key contains path traversal characters")

        # Normalize the path
        normalized = os.path.normpath(validated).replace("\\", "/")
        if normalized.startswith("..") or normalized.startswith("/"):
            raise InputValidationError("S3 key normalization detected path traversal")

        return validated

    def get_object(self, key: str) -> bytes:
        """Retrieve an object from S3."""
        validated_key = self._validate_s3_key(key)

        try:
            response = self._client.get_object(Bucket=S3_BUCKET, Key=validated_key)
            body = response["Body"].read()
            logger.info(
                "S3 object retrieved",
                extra={"bucket": S3_BUCKET, "key": validated_key, "size": len(body)},
            )
            return body
        except ClientError as e:
            logger.error(
                "S3 get_object failed",
                extra={
                    "bucket": S3_BUCKET,
                    "key": validated_key,
                    "error_code": e.response["Error"]["Code"],
                },
            )
            raise

    def put_object(self, key: str, body: bytes, content_type: str = "application/json") -> dict:
        """Store an object in S3 with server-side encryption."""
        validated_key = self._validate_s3_key(key)

        # Validate content type
        allowed_content_types = {
            "application/json",
            "text/plain",
            "application/octet-stream",
            "text/csv",
        }
        if content_type not in allowed_content_types:
            raise InputValidationError(
                f"Invalid content type: must be one of {sorted(allowed_content_types)}"
            )

        if not isinstance(body, bytes):
            raise InputValidationError("Body must be bytes")

        # Enforce size limit (10 MB)
        max_size = 10 * 1024 * 1024
        if len(body) > max_size:
            raise InputValidationError(f"Object size exceeds maximum of {max_size} bytes")

        try:
            self._client.put_object(
                Bucket=S3_BUCKET,
                Key=validated_key,
                Body=body,
                ContentType=content_type,
                ServerSideEncryption="aws:kms",
            )
            logger.info(
                "S3 object stored",
                extra={"bucket": S3_BUCKET, "key": validated_key, "size": len(body)},
            )
            return {"bucket": S3_BUCKET, "key": validated_key, "status": "uploaded"}
        except ClientError as e:
            logger.error(
                "S3 put_object failed",
                extra={
                    "bucket": S3_BUCKET,
                    "key": validated_key,
                    "error_code": e.response["Error"]["Code"],
                },
            )
            raise

    def list_objects(self, prefix: str, max_keys: int = 100) -> list:
        """List objects with a given prefix."""
        validated_prefix = self._validate_s3_key(prefix)

        if not isinstance(max_keys, int) or max_keys < 1 or max_keys > 1000:
            max_keys = 100

        try:
            response = self._client.list_objects_v2(
                Bucket=S3_BUCKET,
                Prefix=validated_prefix,
                MaxKeys=max_keys,
            )
            keys = [obj["Key"] for obj in response.get("Contents", [])]
            logger.info(
                "S3 objects listed",
                extra={"bucket": S3_BUCKET, "prefix": validated_prefix, "count": len(keys)},
            )
            return keys
        except ClientError as e:
            logger.error(
                "S3 list_objects failed",
                extra={
                    "bucket": S3_BUCKET,
                    "prefix": validated_prefix,
                    "error_code": e.response["Error"]["Code"],
                },
            )
            raise


class SNSService:
    """Secure SNS publishing with input validation."""

    def __init__(self):
        self._client = get_boto3_client("sns")

    def publish(self, message: dict, subject: str = "Microservice Notification") -> dict:
        """Publish a message to SNS topic."""
        if not SNS_TOPIC_ARN:
            raise ValueError("SNS_TOPIC_ARN environment variable not configured")

        # Validate the topic ARN format
        if not re.match(
            r"^arn:aws:sns:[a-z0-9-]+:\d{12}:microservices-[a-zA-Z0-9\-]+$",
            SNS_TOPIC_ARN,
        ):
            raise InputValidationError("Invalid SNS topic ARN format")

        # Validate subject
        if not isinstance(subject, str) or len(subject) > 100:
            raise InputValidationError("Subject must be a string of max 100 characters")
        subject = re.sub(r"[^\w\s\-.]", "", subject)

        # Sanitize message before publishing
        sanitized_message = sanitize_for_logging(message)
        message_json = json.dumps(sanitized_message, default=str)

        if len(message_json) > 256 * 1024:  # SNS message size limit
            raise InputValidationError("Message exceeds SNS size limit")

        try:
            response = self._client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=message_json,
                Subject=subject,
            )
            message_id = response["MessageId"]
            logger.info("SNS message published", extra={"message_id": message_id})
            return {"message_id": message_id, "status": "published"}
        except ClientError as e:
            logger.error(
                "SNS publish failed",
                extra={"error_code": e.response["Error"]["Code"]},
            )
            raise


class SQSService:
    """Secure SQS operations with input validation."""

    def __init__(self):
        self._client = get_boto3_client("sqs")

    def send_message(self, message: dict, delay_seconds: int = 0) -> dict:
        """Send a message to SQS queue."""
        if not SQS_QUEUE_URL:
            raise ValueError("SQS_QUEUE_URL environment variable not configured")

        # Validate queue URL format
        if not re.match(
            r"^https://sqs\.[a-z0-9-]+\.amazonaws\.com/\d{12}/microservices-[a-zA-Z0-9\-]+$",
            SQS_QUEUE_URL,
        ):
            raise InputValidationError("Invalid SQS queue URL format")

        # Validate delay
        if not isinstance(delay_seconds, int) or delay_seconds < 0 or delay_seconds > 900:
            raise InputValidationError("delay_seconds must be between 0 and 900")

        # Sanitize message
        sanitized_message = sanitize_for_logging(message)
        message_body = json.dumps(sanitized_message, default=str)

        if len(message_body) > 256 * 1024:  # SQS message size limit
            raise InputValidationError("Message exceeds SQS size limit")

        try:
            response = self._client.send_message(
                QueueUrl=SQS_QUEUE_URL,
                MessageBody=message_body,
                DelaySeconds=delay_seconds,
            )
            message_id = response["MessageId"]
            logger.info("SQS message sent", extra={"message_id": message_id})
            return {"message_id": message_id, "status": "enqueued"}
        except ClientError as e:
            logger.error(
                "SQS send_message failed",
                extra={"error_code": e.response["Error"]["Code"]},
            )
            raise


