def build_response(status_code: int, body: dict, headers: Optional[dict] = None) -> dict:
    """Build a standardized API Gateway response with security headers."""
    default_headers = {
        "Content-Type": "application/json",
        "X-Content-Type-Options": "nosniff",
        "X-Frame-Options": "DENY",
        "Cache-Control": "no-store, no-cache, must-revalidate",
        "Strict-Transport-Security": "max-age=31536000; includeSubDomains",
        "X-Request-Id": "",  # Will be set per-request
    }
    if headers:
        default_headers.update(headers)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body, default=str),
    }


@require_auth
def lambda_handler(event: dict, context) -> dict:
    """
    Main Lambda handler for the microservice.
    
    Supports the following actions via API Gateway:
    - GET /items/{id} -> get item from DynamoDB
    - PUT /items/{id} -> store item in DynamoDB
    - DELETE /items/{id} -> delete item from DynamoDB
    - POST /files -> upload to S3
    - GET /files?prefix=xxx -> list S3 objects
    - POST /notify -> publish to SNS
    - POST /enqueue -> send to SQS
    """
    request_id = getattr(context, "aws_request_id", "unknown") if context else "unknown"

    logger.info(
        "Request received",
        extra={
            "request_id": request_id,
            "path": event.get("path", ""),
            "method": event.get("httpMethod", ""),
        },
    )

    try:
        http_method = event.get("httpMethod", "GET").upper()
        path = event.get("path", "/")
        path_params = event.get("pathParameters") or {}
        query_params = event.get("queryStringParameters") or {}
        body = validate_request_body(event.get("body"))

        # Route handling
        if path.startswith("/items"):
            item_id = path_params.get("id")

            if http_method == "GET" and item_id:
                validated_id = validate_string_input(item_id, "item_id", ALLOWED_ID_PATTERN)
                result = get_dynamodb_service().get_item(validated_id)
                if result is None:
                    return build_response(
                        404,
                        {"error": "Item not found"},
                        {"X-Request-Id": request_id},
                    )
                # Sanitize before returning
                return build_response(
                    200,
                    {"item": sanitize_for_logging(result)},
                    {"X-Request-Id": request_id},
                )

            elif http_method == "PUT" and item_id:
                validated_id = validate_string_input(item_id, "item_id", ALLOWED_ID_PATTERN)
                result = get_dynamodb_service().put_item(validated_id, body)
                return build_response(
                    201,
                    result,
                    {"X-Request-Id": request_id},
                )

            elif http_method == "DELETE" and item_id:
                validated_id = validate_string_input(item_id, "item_id", ALLOWED_ID_PATTERN)
                result = get_dynamodb_service().delete_item(validated_id)
                return build_response(
                    200,
                    result,
                    {"X-Request-Id": request_id},
                )

        elif path.startswith("/files"):
            if http_method == "GET":
                prefix = validate_string_input(
                    query_params.get("prefix", "data/"),
                    "prefix",
                    ALLOWED_S3_KEY_PATTERN,
                    required=False,
                ) or "data/"
                max_keys = min(int(query_params.get("max_keys", "100")), 1000)
                result = get_s3_service().list_objects(prefix, max_keys)
                return build_response(
                    200,
                    {"files": result},
                    {"X-Request-Id": request_id},
                )

            elif http_method == "POST":
                key = validate_string_input(
                    body.get("key"), "key", ALLOWED_S3_KEY_PATTERN
                )
                content = body.get("content", "")
                if isinstance(content, str):
                    content = content.encode("utf-8")
                content_type = body.get("content_type", "application/json")
                result = get_s3_service().put_object(key, content, content_type)
                return build_response(
                    201,
                    result,
                    {"X-Request-Id": request_id},
                )

        elif path == "/notify" and http_method == "POST":
            subject = body.get("subject", "Microservice Notification")
            message = body.get("message", {})
            if not isinstance(message, dict):
                raise InputValidationError("Message must be a JSON object")
            result = get_sns_service().publish(message, subject)
            return build_response(
                200,
                result,
                {"X-Request-Id": request_id},
            )

        elif path == "/enqueue" and http_method == "POST":
            message = body.get("message", {})
            if not isinstance(message, dict):
                raise InputValidationError("Message must be a JSON object")
            delay = int(body.get("delay_seconds", 0))
            result = get_sqs_service().send_message(message, delay)
            return build_response(
                200,
                result,
                {"X-Request-Id": request_id},
            )

        elif path == "/health" and http_method == "GET":
            return build_response(
                200,
                {
                    "status": "healthy",
                    "environment": ENVIRONMENT,
                    "function_name": getattr(context, "function_name", "unknown") if context else "unknown",
                },
                {"X-Request-Id": request_id},
            )

        # No matching route
        return build_response(
            404,
            {"error": "Not found"},
            {"X-Request-Id": request_id},
        )

    except InputValidationError as e:
        logger.warning("Input validation failed", extra={"error": str(e), "request_id": request_id})
        return build_response(
            400,
            {"error": "Bad request", "detail": str(e)},
            {"X-Request-Id": request_id},
        )

    except AuthorizationError as e:
        logger.warning("Authorization failed", extra={"error": str(e), "request_id": request_id})
        return build_response(
            403,
            {"error": "Forbidden"},
            {"X-Request-Id": request_id},
        )

    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        logger.error(
            "AWS service error",
            extra={"error_code": error_code, "request_id": request_id},
        )

        if error_code in ("AccessDeniedException", "UnauthorizedAccess"):
            return build_response(
                403,
                {"error": "Access denied"},
                {"X-Request-Id": request_id},
            )
        elif error_code == "ResourceNotFoundException":
            return build_response(
                404,
                {"error": "Resource not found"},
                {"X-Request-Id": request_id},
            )
        elif error_code in ("ThrottlingException", "ProvisionedThroughputExceededException"):
            return build_response(
                429,
                {"error": "Too many requests"},
                {"X-Request-Id": request_id, "Retry-After": "5"},
            )
        else:
            return build_response(
                500,
                {"error": "Internal server error"},
                {"X-Request-Id": request_id},
            )

    except Exception:
        # Never expose internal error details to the caller
        logger.exception("Unhandled exception", extra={"request_id": request_id})
        return build_response(
            500,
            {"error": "Internal server error"},
            {"X-Request-Id": request_id},
        )